DROP TRIGGER IF EXISTS tbiu_sc_lon_m_rule ON sc_lon_m_rule CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_lon_m_rule() RETURNS trigger AS $BODY$
declare
  li_rc integer;li_year integer;
BEGIN
  BEGIN
--return ;
  if coalesce(NEW.sort_order::text, '') = '' then NEW.sort_order := 0;end if;
  if coalesce(NEW.maximum_loan_amount::text, '') = '' then NEW.maximum_loan_amount := 0;end if;
  if coalesce(NEW.maximum_loan_salary::text, '') = '' then NEW.maximum_loan_salary := 0;end if;
  if coalesce(NEW.minimum_loan_amount::text, '') = '' then NEW.minimum_loan_amount := 0;end if;
  if coalesce(NEW.use_total_value_of_collateral::text, '') = '' then NEW.use_total_value_of_collateral := 0;end if;
  if coalesce(NEW.loan_payment_type_code::text, '') = '' or NEW.loan_payment_type_code = ' ' then NEW.loan_payment_type_code :='01';end if;
  if coalesce(NEW.steprate_principal_percent::text, '') = '' then NEW.steprate_principal_percent := 0;end if;
  if coalesce(NEW.minimum_term_employee::text, '') = '' then NEW.minimum_term_employee := 0;end if;
  if coalesce(NEW.minimum_term_employee_m::text, '') = '' then NEW.minimum_term_employee_m := '0';end if;
  if coalesce(NEW.minimum_term_of_member::text, '') = '' then NEW.minimum_term_of_member :=0;end if;
  if coalesce(NEW.minimum_term_of_member_m::text, '') = '' then NEW.minimum_term_of_member_m :='0';end if;
  if coalesce(NEW.age_limit::text, '') = '' then NEW.age_limit :=0;end if;
  if coalesce(NEW.max_withdraw_period::text, '') = '' then NEW.max_withdraw_period :=0;end if;
  if coalesce(NEW.maximum_loan_installment::text, '') = '' then NEW.maximum_loan_installment :=0;end if;
  if coalesce(NEW.backlist_count::text, '') = '' then NEW.backlist_count := 0;end if;
  if coalesce(NEW.last_period_morethan::text, '') = '' then NEW.last_period_morethan := '0';end if;
  if coalesce(NEW.permit_type::text, '') = '' or NEW.permit_type = ' ' then NEW.permit_type :='01';end if;
  if coalesce(NEW.othercoll_comparetype::text, '') = '' then NEW.othercoll_comparetype := '0';end if;
  if coalesce(NEW.min_share_value::text, '') = '' then NEW.min_share_value :=0;end if;
  if coalesce(NEW.min_share_value_m::text, '') = '' then NEW.min_share_value_m :='0';end if;
  if coalesce(NEW.salary_balance::text, '') = '' then NEW.salary_balance :=0;end if;
  if coalesce(NEW.salary_balance_m::text, '') = '' then NEW.salary_balance_m :='0';end if;
  if coalesce(NEW.salary_less::text, '') = '' then NEW.salary_less :=0;end if;
  if coalesce(NEW.salary_less_m::text, '') = '' then NEW.salary_less_m :=0;end if;
  if coalesce(NEW.min_payment_installment::text, '') = '' then NEW.min_payment_installment :=0;end if;
  if coalesce(NEW.min_payment_percent::text, '') = '' then NEW.min_payment_percent :=0;end if;
  if coalesce(NEW.intreturn_round_status::text, '') = '' then NEW.intreturn_round_status :='0';end if;
  if coalesce(NEW.count_period_loan_type::text, '') = '' or NEW.count_period_loan_type =' ' then NEW.count_period_loan_type :='0';end if;
  if coalesce(NEW.percent_sal_spouse::text, '') = '' then NEW.percent_sal_spouse := 0;end if;
  if coalesce(NEW.att_loan_permit::text, '') = '' then NEW.att_loan_permit := 0;end if;
  if coalesce(NEW.spec_payment_calc_method::text, '') = '' or NEW.spec_payment_calc_method=' ' then NEW.spec_payment_calc_method :='01';end if;
  if coalesce(NEW.round_method_install::text, '') = '' then NEW.round_method_install := 0;end if;
  if coalesce(NEW.round_method::text, '') = '' then NEW.round_method := 0;end if;
  if coalesce(NEW.type_round_method::text, '') = '' or NEW.type_round_method = ' 'then NEW.type_round_method :='-';end if;
  if coalesce(NEW.intreturn_type_round_method::text, '') = '' or NEW.intreturn_type_round_method = ''  then NEW.intreturn_type_round_method :='0';end if;
  if coalesce(NEW.atm_status::text, '') = '' or NEW.atm_status = ' ' then NEW.atm_status :='0';end if;
  if coalesce(NEW.fixed_payment::text, '') = '' then NEW.fixed_payment := 0;end if;
  if coalesce(NEW.fund_status::text, '') = '' or NEW.fund_status = ' ' then NEW.fund_status := '0';end if;
  if coalesce(NEW.coll_age_consider::text, '') = '' or NEW.coll_age_consider = ' ' then NEW.coll_age_consider := '0';end if;
  if coalesce(NEW.intmonth_round_status::text, '') = '' or NEW.intmonth_round_status = ' ' then NEW.intmonth_round_status := '0';end if;
  if coalesce(NEW.intmonth_round_method::text, '') = '' then NEW.intmonth_round_method := 0;end if;
  if coalesce(NEW.intmonth_type_round_method::text, '') = '' or NEW.intmonth_type_round_method = ' ' then NEW.intmonth_type_round_method :='0';end if;
  if coalesce(NEW.review_loan_number::text, '') = '' then NEW.review_loan_number := 0;end if;
  if coalesce(NEW.review_loan_type::text, '') = '' or NEW.review_loan_type = ' ' then NEW.review_loan_type := 'D';end if;
  if coalesce(NEW.increment_interest_rate::text, '') = '' then NEW.increment_interest_rate := 0;end if;
  if coalesce(NEW.multi_objecttive::text, '') = '' or NEW.multi_objecttive = ' ' then NEW.multi_objecttive := '0';end if;
  if coalesce(NEW.paynextmonth_cutpending::text, '') = '' or NEW.paynextmonth_cutpending = ' ' then NEW.paynextmonth_cutpending := '0';end if;
  if coalesce(NEW.payint_firstperiod_status::text, '') = '' or NEW.payint_firstperiod_status = ' ' then NEW.payint_firstperiod_status := '0';end if;
  if coalesce(NEW.own_member_age_sum_status::text, '') = '' or NEW.own_member_age_sum_status = ' ' then NEW.own_member_age_sum_status := '0';end if;
  if coalesce(NEW.own_work_age_status::text, '') = '' or NEW.own_work_age_status = ' ' then NEW.own_work_age_status := '0';end if;
  if coalesce(NEW.payloan_at_approve_status::text, '') = '' or NEW.payloan_at_approve_status = ' ' then NEW.payloan_at_approve_status := '0';end if;
  if coalesce(NEW.pay_loan_period::text, '') = '' or NEW.pay_loan_period = ' ' then NEW.pay_loan_period := '0';end if;
  if coalesce(NEW.cal_first_int_type::text, '') = '' or NEW.cal_first_int_type = ' ' then NEW.cal_first_int_type :='0';end if;
  if coalesce(NEW.cal_old_int_type::text, '') = '' or NEW.cal_old_int_type = ' ' then NEW.cal_old_int_type :='0';end if;
  if coalesce(NEW.max_permit_day::text, '') = '' then NEW.max_permit_day := 0;end if;
  if coalesce(NEW.welfare_percent::text, '') = '' then NEW.welfare_percent := 0;end if;
  if coalesce(NEW.salbal_notother::text, '') = '' or NEW.salbal_notother = ' ' then NEW.salbal_notother := '0';end if;
  if coalesce(NEW.keeping_groupreport::text, '') = ''  or NEW.keeping_groupreport = ' ' then NEW.keeping_groupreport := '01';end if;
  if coalesce(NEW.loan_looping::text, '') = '' or NEW.loan_looping =' ' then NEW.loan_looping := '0';end if;
  if coalesce(NEW.calint_history_more::text, '') = '' or NEW.calint_history_more = ' ' then NEW.calint_history_more := '0';end if;
  if coalesce(NEW.calint_tyelevel::text, '') = '' or NEW.calint_tyelevel = ' ' then NEW.calint_tyelevel := '0';end if;
  if coalesce(NEW.calint_fixed_time::text, '') = '' or NEW.calint_fixed_time = ' ' then NEW.calint_fixed_time := '0';end if;
  if coalesce(NEW.loan_limit_control::text, '') = '' then NEW.loan_limit_control := 0;end if;
  if coalesce(NEW.pay_permit_status::text, '') = '' or NEW.pay_permit_status = ' ' then NEW.pay_permit_status := '0';end if;
  if coalesce(NEW.startkeep_nextmonth::text, '') = '' or NEW.startkeep_nextmonth = ' ' then NEW.startkeep_nextmonth := '0';end if;
  if coalesce(NEW.drop_prin_status::text, '') = '' or NEW.drop_prin_status = ' ' then NEW.drop_prin_status := '0';end if;
  if coalesce(NEW.req_payment::text, '') = '' or NEW.req_payment = ' '  then NEW.req_payment := 'CSH';end if;
  if coalesce(NEW.retire_share_limit_loan::text, '') = '' then NEW.retire_share_limit_loan := 0;end if;
  if coalesce(NEW.retire_loan_install::text, '') = '' then NEW.retire_loan_install := 0;end if;
  if coalesce(NEW.lon_insure_status::text, '') = '' or NEW.lon_insure_status = ' ' then NEW.lon_insure_status := '0';end if;
  if coalesce(NEW.startkeep_frommainrule::text, '') = '' or NEW.startkeep_frommainrule = ' ' then NEW.startkeep_frommainrule :='0';end if;
  if coalesce(NEW.priority_keep_coll::text, '') = '' or NEW.priority_keep_coll = ' '  then NEW.priority_keep_coll := '00';end if;
  if coalesce(NEW.not_cal_npl::text, '') = '' or NEW.not_cal_npl = ' ' then NEW.not_cal_npl := '0';end if;



  if coalesce(trim(both OLD.loan_type)::text, '') = '' and (trim(both NEW.loan_type) IS NOT NULL AND (trim(both NEW.loan_type))::text <> '')  then

    -- เพิ่ม coll_rule    
    select count(1) into STRICT li_rc
    from sc_lon_m_coll_rule
    where loan_type = NEW.loan_type;
    if coalesce(li_rc::text, '') = '' or li_rc = 0 then
      insert into sc_lon_m_coll_rule(loan_type )
      values (NEW.loan_type  );
    end if;


    -- เพิ่มเลขที่เอกสาร
    select count(1) into STRICT li_rc
    from sc_cnt_m_document_no_control
    where document_code = 'LONCONTRACTNO'||trim(both NEW.ref_contract_type);

    if coalesce(li_rc::text, '') = '' or li_rc = 0 then
      -- ปีเอกสาร
      BEGIN
        select max( document_year ) into STRICT li_year
        from sc_cnt_m_document_no_control
        where document_code like 'LONCONTRACTNO%'
        and exists (
          SELECT null from sc_lon_m_rule
          where loan_type = substr(sc_cnt_m_document_no_control.document_code,13,2)
        ) 
        order by document_code;
      exception when others then li_year := to_char(statement_timestamp(),'yyyy');
      end;

      -- เลขที่เอกสารคำขอ
      insert into sc_cnt_m_document_no_control(
        document_code   , document_name   , last_document_no
        , document_year , application  ,visible_status
      )values (
        'LONREQNO'||trim(both NEW.ref_contract_type) , 'เลขที่คำขอ : '||trim(both trim(both NEW.loan_type_description)) , '000000'
        , li_year   , 'teller'  ,'0'
      );

      -- เลขที่สัญญา`
      insert into sc_cnt_m_document_no_control(
        document_code   , document_name   , last_document_no
        , document_year , application  ,visible_status
        , life_time
      )values (
        'LONCONTRACTNO'||trim(both NEW.ref_contract_type) , 'เลขที่สัญญา : '||trim(both trim(both NEW.loan_type_description)) , '00000'
        , '0000'   , 'teller'  ,'1'
        , '0'
      );

    end if;

  end if;

--Niorn 2023-05-27 เงินกู้ ATM transfer_status ต้องเป็น 0 
--เพราะต้อง สร้างใบเสร็จหนี้เก่า money_type = TRL เพื่อให้ ดอกเบี้ยค้างสัญญาเก่า ย้ายไปสัญญาใหม่
if NEW.atm_status ='1' then
    NEW.transfer_status := '0';
end if;

--Niorn 2023-08-28 TGE ขอบเขตการมอง ประเภทเดียวกันดูจาก loan_group_coll
if coalesce(NEW.loan_group_coll::text, '') = '' or NEW.loan_group_coll = ' ' then NEW.loan_group_coll := NEW.loan_group_code;end if;
--Niorn 2023-12-31 MWA 
if coalesce(NEW.invest_status::text, '') = '' or NEW.invest_status = ' ' then NEW.invest_status := '0';end if;

--Niorn 2024-06-20 MWA 
if coalesce(NEW.group_loan::text, '') = '' or NEW.group_loan = ' ' then NEW.group_loan := '00';end if;

--Niorn 2024-10-30 BOT 
if coalesce(NEW.ncb_nosend_status::text, '') = '' or NEW.ncb_nosend_status = ' ' then NEW.ncb_nosend_status := '0';end if;


  END;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
